#include <stdio.h>
#define MAX_BITS 64
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        unsigned int n; scanf("%u",&n);
        if(n==0){ printf("0\n"); continue; }
        int top=-1; int stack[MAX_BITS];
        while(n>0){ stack[++top]=n&1; n>>=1; }
        while(top>=0) printf("%d",stack[top--]);
        printf("\n");
    }
    return 0;
}

