#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        unsigned int n; cin>>n;
        if(n==0){ cout<<'0'<<'\n'; continue; }
        vector<char> st;
        while(n){ st.push_back('0'+(n&1)); n>>=1; }
        for(auto it=st.rbegin(); it!=st.rend(); ++it) cout<<*it;
        cout<<'\n';
    }
    return 0;
}

