const fs = require('fs');
const input = fs.readFileSync(0,'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let res = [];
for(let i=0;i<T;i++){
  let n = Number(input[idx++]);
  if(n===0){ res.push('0'); continue; }
  let stack = [];
  while(n>0){ stack.push(n%2); n = Math.floor(n/2); }
  res.push(stack.reverse().join(''));
}
